	"time"

	"github.com/google/uuid"
)

// Domain-level errors. Layers above translate these to HTTP statuses.
var (
	ErrNotFound       = errors.New("resource not found")
	ErrInvalidInput   = errors.New("invalid input")
	ErrCapacityExceed = errors.New("capacity exceeded")
	ErrConflict       = errors.New("conflicting state")
)

// BookingStatus enumerates the lifecycle of a booking.
type BookingStatus string

const (
	BookingStatusPending   BookingStatus = "pending"
	BookingStatusConfirmed BookingStatus = "confirmed"
	BookingStatusCancelled BookingStatus = "cancelled"
	BookingStatusCompleted BookingStatus = "completed"
)

// Booking represents a single guest reservation at a HarborWorks property.
type Booking struct {
	ID          uuid.UUID     `json:"id"`
	GroupID     *uuid.UUID    `json:"group_id,omitempty"`
	GuestName   string        `json:"guest_name"`
	GuestEmail  string        `json:"guest_email"`
	PartySize   int           `json:"party_size"`
	CheckIn     time.Time     `json:"check_in"`
	CheckOut    time.Time     `json:"check_out"`
	Status      BookingStatus `json:"status"`
	TotalCents  int64         `json:"total_cents"`
	CreatedAt   time.Time     `json:"created_at"`
	UpdatedAt   time.Time     `json:"updated_at"`
}

// Validate enforces invariants that hold regardless of persistence layer.
func (b *Booking) Validate() error {
	if b.GuestName == "" {
		return errors.Join(ErrInvalidInput, errors.New("guest_name is required"))
	}
	if b.GuestEmail == "" {
		return errors.Join(ErrInvalidInput, errors.New("guest_email is required"))
	}
	if b.PartySize <= 0 {
		return errors.Join(ErrInvalidInput, errors.New("party_size must be > 0"))
	}
	if !b.CheckOut.After(b.CheckIn) {
		return errors.Join(ErrInvalidInput, errors.New("check_out must be after check_in"))
	}
	return nil
}

// GroupReservation aggregates many bookings under one organising entity.
type GroupReservation struct {
	ID            uuid.UUID `json:"id"`
	Name          string    `json:"name"`
	OrganizerName string    `json:"organizer_name"`
	OrganizerEmail string   `json:"organizer_email"`
	Capacity      int       `json:"capacity"`
	Notes         string    `json:"notes"`
	CreatedAt     time.Time `json:"created_at"`
	UpdatedAt     time.Time `json:"updated_at"`

	// Bookings is populated when the aggregate is loaded with children.
	Bookings []Booking `json:"bookings,omitempty"`
}

func (g *GroupReservation) Validate() error {
	if g.Name == "" {
		return errors.Join(ErrInvalidInput, errors.New("name is required"))
	}
	if g.OrganizerEmail == "" {
		return errors.Join(ErrInvalidInput, errors.New("organizer_email is required"))
	}
	if g.Capacity <= 0 {
		return errors.Join(ErrInvalidInput, errors.New("capacity must be > 0"))
	}
	return nil
}

// CurrentHeadcount returns the sum of party sizes of non-cancelled bookings.
func (g *GroupReservation) CurrentHeadcount() int {
	total := 0
	for _, b := range g.Bookings {
		if b.Status == BookingStatusCancelled {
			continue
		}
		total += b.PartySize
	}
	return total
}
"}

