)

// GroupService coordinates group reservation aggregates and their child bookings.
type GroupService struct {
	groups   repository.GroupRepository
	bookings repository.BookingRepository
	log      *slog.Logger
}

func NewGroupService(groups repository.GroupRepository, bookings repository.BookingRepository, log *slog.Logger) *GroupService {
	return &GroupService{groups: groups, bookings: bookings, log: log}
}

func (s *GroupService) Create(ctx context.Context, g *domain.GroupReservation) (*domain.GroupReservation, error) {
	if err := g.Validate(); err != nil {
		return nil, err
	}
	if err := s.groups.Create(ctx, g); err != nil {
		s.log.Error("create group failed", "error", err, "name", g.Name)
		return nil, err
	}
	s.log.Info("group created", "id", g.ID, "name", g.Name)
	return g, nil
}

func (s *GroupService) Get(ctx context.Context, id uuid.UUID) (*domain.GroupReservation, error) {
	g, err := s.groups.Get(ctx, id)
	if err != nil {
		return nil, err
	}
	bookings, err := s.bookings.ListByGroup(ctx, id)
	if err != nil {
		return nil, err
	}
	g.Bookings = bookings
	return g, nil
}

func (s *GroupService) List(ctx context.Context, limit, offset int) ([]domain.GroupReservation, error) {
	return s.groups.List(ctx, limit, offset)
}

// AddBooking adds a booking to an existing group, enforcing the group capacity.
func (s *GroupService) AddBooking(ctx context.Context, groupID uuid.UUID, b *domain.Booking) (*domain.Booking, error) {
	g, err := s.groups.Get(ctx, groupID)
	if err != nil {
		return nil, err
	}

	existing, err := s.bookings.ListByGroup(ctx, groupID)
	if err != nil {
		return nil, err
	}
	g.Bookings = existing

	b.GroupID = &groupID
	if b.Status == "" {
		b.Status = domain.BookingStatusPending
	}
	if err := b.Validate(); err != nil {
		return nil, err
	}

	projected := g.CurrentHeadcount() + b.PartySize
	if projected > g.Capacity {
		return nil, errors.Join(domain.ErrCapacityExceed,
			errors.New("group capacity would be exceeded"))
	}

	if err := s.bookings.Create(ctx, b); err != nil {
		return nil, err
	}
	s.log.Info("group booking added",
		"group_id", groupID, "booking_id", b.ID, "headcount", projected, "capacity", g.Capacity)
	return b, nil
}

func (s *GroupService) Delete(ctx context.Context, id uuid.UUID) error {
	return s.groups.Delete(ctx, id)
}
"}

