import (
	"errors"
	"log/slog"
	"net/http"
	"strconv"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/google/uuid"

	"github.com/harborworks/booking-hub/internal/domain"
	"github.com/harborworks/booking-hub/internal/service"
	"github.com/harborworks/booking-hub/internal/views"
)

type BookingHandler struct {
	svc *service.BookingService
	log *slog.Logger
}

func NewBookingHandler(svc *service.BookingService, log *slog.Logger) *BookingHandler {
	return &BookingHandler{svc: svc, log: log}
}

type bookingRequest struct {
	GroupID    string `json:"group_id" form:"group_id"`
	GuestName  string `json:"guest_name" form:"guest_name" binding:"required"`
	GuestEmail string `json:"guest_email" form:"guest_email" binding:"required,email"`
	PartySize  int    `json:"party_size" form:"party_size" binding:"required,min=1"`
	CheckIn    string `json:"check_in" form:"check_in" binding:"required"`
	CheckOut   string `json:"check_out" form:"check_out" binding:"required"`
	TotalCents int64  `json:"total_cents" form:"total_cents"`
}

func (h *BookingHandler) parseRequest(c *gin.Context) (*domain.Booking, error) {
	var req bookingRequest
	if err := c.ShouldBind(&req); err != nil {
		return nil, err
	}
	checkIn, err := time.Parse(time.RFC3339, req.CheckIn)
	if err != nil {
		// fallback to YYYY-MM-DD form input
		checkIn, err = time.Parse("2006-01-02", req.CheckIn)
		if err != nil {
			return nil, errors.New("check_in must be RFC3339 or YYYY-MM-DD")
		}
	}
	checkOut, err := time.Parse(time.RFC3339, req.CheckOut)
	if err != nil {
		checkOut, err = time.Parse("2006-01-02", req.CheckOut)
		if err != nil {
			return nil, errors.New("check_out must be RFC3339 or YYYY-MM-DD")
		}
	}
	b := &domain.Booking{
		GuestName:  req.GuestName,
		GuestEmail: req.GuestEmail,
		PartySize:  req.PartySize,
		CheckIn:    checkIn,
		CheckOut:   checkOut,
		TotalCents: req.TotalCents,
	}
	if req.GroupID != "" {
		gid, err := uuid.Parse(req.GroupID)
		if err != nil {
			return nil, errors.New("group_id must be a valid UUID")
		}
		b.GroupID = &gid
	}
	return b, nil
}

// POST /api/bookings
func (h *BookingHandler) Create(c *gin.Context) {
	b, err := h.parseRequest(c)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}
	created, err := h.svc.Create(c.Request.Context(), b)
	if err != nil {
		writeServiceError(c, err)
		return
	}
	c.JSON(http.StatusCreated, created)
}

