{"file_path": "/home/mint/Desktop/projects/task-08/repo/internal/api/router.go", "content": "package api

import (
	"log/slog"
	"net/http"

	"github.com/gin-gonic/gin"

	"github.com/harborworks/booking-hub/internal/api/handlers"
	"github.com/harborworks/booking-hub/internal/api/middleware"
)

// Deps groups everything required by the router so wiring stays explicit.
type Deps struct {
	Logger         *slog.Logger
	BookingHandler *handlers.BookingHandler
	GroupHandler   *handlers.GroupHandler
	HealthHandler  *handlers.HealthHandler
}

// NewRouter constructs the gin engine with all routes and middleware.
func NewRouter(d Deps) http.Handler {
	gin.SetMode(gin.ReleaseMode)

	r := gin.New()
	r.Use(middleware.Recovery(d.Logger))
	r.Use(middleware.RequestLogger(d.Logger))

	// Health endpoints (unauthenticated, used by docker compose).
	r.GET("/healthz", d.HealthHandler.Liveness)
	r.GET("/readyz", d.HealthHandler.Readiness)

	// HTML pages
	r.GET("/", d.BookingHandler.Index)
	r.GET("/groups", d.GroupHandler.IndexHTML)
	r.GET("/groups/:id", d.GroupHandler.DetailHTML)

	// JSON API
	api := r.Group("/api")
	{
		bookings := api.Group("/bookings")
		{
			bookings.POST("", d.BookingHandler.Create)
			bookings.GET("", d.BookingHandler.List)
			bookings.GET("/:id", d.BookingHandler.Get)
			bookings.POST("/:id/confirm", d.BookingHandler.Confirm)
			bookings.POST("/:id/cancel", d.BookingHandler.Cancel)
		}
		groups := api.Group("/groups")
		{
			groups.POST("", d.GroupHandler.Create)
			groups.GET("", d.GroupHandler.List)
			groups.GET("/:id", d.GroupHandler.Get)
			groups.POST("/:id/bookings", d.GroupHandler.AddBooking)
		}
	}

	return r
}
"}

