	tag, err := r.pool.Exec(ctx, `DELETE FROM bookings WHERE id = $1`, id)
	if err != nil {
		return fmt.Errorf("delete booking: %w", err)
	}
	if tag.RowsAffected() == 0 {
		return domain.ErrNotFound
	}
	return nil
}

// --- helpers ---

type rowScanner interface {
	Scan(dest ...any) error
}

func sanitisePaging(limit, offset int) (int, int) {
	if limit <= 0 || limit > 200 {
		limit = 50
	}
	if offset < 0 {
		offset = 0
	}
	return limit, offset
}

func scanBooking(s rowScanner) (*domain.Booking, error) {
	var (
		b       domain.Booking
		groupID *uuid.UUID
		status  string
	)
	if err := s.Scan(
		&b.ID, &b.UserID, &b.ResourceID, &groupID, &b.PartySize,
		&b.StartTime, &b.EndTime, &status, &b.Notes, &b.CreatedAt, &b.UpdatedAt,
	); err != nil {
		return nil, err
	}
	b.GroupID = groupID
	b.Status = domain.BookingStatus(status)
	return &b, nil
}

func collectBookings(rows pgx.Rows) ([]domain.Booking, error) {
	out := make([]domain.Booking, 0, 16)
	for rows.Next() {
		b, err := scanBooking(rows)
		if err != nil {
			return nil, err
		}
		out = append(out, *b)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return out, nil
}
"}

