				* { box-sizing: border-box; }
				body { margin:0; font-family: system-ui, -apple-system, sans-serif; background: var(--bg); color: var(--fg); }
				header { background: var(--card); padding: 1rem 2rem; display:flex; justify-content:space-between; align-items:center; border-bottom: 2px solid var(--accent); flex-wrap:wrap; gap:1rem; }
				header h1 { margin:0; font-size:1.2rem; letter-spacing:0.5px; }
				header nav a { color: var(--fg); margin-left: 1.2rem; text-decoration:none; font-weight:500; font-size:0.95rem; }
				header nav a:hover { color: var(--accent); }
				.userbox { color: var(--muted); font-size:0.9rem; }
