				h2 { color: var(--accent); margin-top: 0; }
				h3 { color: var(--accent); }
				table { width:100%; border-collapse: collapse; background: var(--card); border-radius:8px; overflow:hidden; }
				th, td { padding: 0.75rem 1rem; text-align: left; border-bottom: 1px solid #1f4865; }
				th { background:#11283b; color: var(--muted); text-transform: uppercase; font-size: 0.75rem; }
				tr:last-child td { border-bottom: none; }
				.badge { display:inline-block; padding:0.15rem 0.6rem; border-radius:999px; font-size:0.7rem; text-transform:uppercase; }
