				.badge.canceled { background:#5a1f1f; color:#ff8a8a; }
				.empty { padding: 2rem; text-align: center; color: var(--muted); background: var(--card); border-radius:8px; }
				.card { background: var(--card); border-radius:8px; padding:1.5rem; margin-bottom:1.5rem; }
				form.stacked { display: grid; gap: 0.8rem; max-width: 480px; }
