				form.stacked input, form.stacked select, form.stacked textarea {
					background:#0b1d2a; color:var(--fg); border:1px solid #2a4a68; border-radius:6px; padding:0.55rem 0.7rem; font-size:1rem;
				}
				form.stacked button {
					background: var(--accent); color:#062028; border:none; border-radius:6px; padding:0.7rem 1rem; font-weight:600; cursor:pointer; font-size:1rem;
				}
				form.stacked button:hover { filter: brightness(1.1); }
				.error { background: #3a1414; border-left: 3px solid var(--err); padding: 0.6rem 1rem; border-radius: 4px; color: var(--err); margin-bottom: 1rem; }
				.warn  { background: #3a2914; border-left: 3px solid #ffcb6b; padding: 0.6rem 1rem; border-radius: 4px; color: #ffcb6b; margin-bottom: 1rem; }
				.ok    { background: #143a24; border-left: 3px solid var(--ok); padding: 0.6rem 1rem; border-radius: 4px; color: var(--ok); margin-bottom: 1rem; }
