				* { box-sizing: border-box; }
				body { margin:0; font-family: system-ui, -apple-system, sans-serif; background: var(--bg); color: var(--fg); }
				header { background: var(--card); padding: 1rem 2rem; display:flex; justify-content:space-between; align-items:center; border-bottom: 2px solid var(--accent); flex-wrap:wrap; gap:1rem; }
				header h1 { margin:0; font-size:1.2rem; letter-spacing:0.5px; }
				header nav a { color: var(--fg); margin-left: 1.2rem; text-decoration:none; font-weight:500; font-size:0.95rem; }
				header nav a:hover { color: var(--accent); }
				.userbox { color: var(--muted); font-size:0.9rem; }
				.userbox strong { color: var(--fg); }
				main { max-width: 1100px; margin: 0 auto; padding: 2rem; }
				h2 { color: var(--accent); margin-top: 0; }
				h3 { color: var(--accent); }
				table { width:100%; border-collapse: collapse; background: var(--card); border-radius:8px; overflow:hidden; }
				th, td { padding: 0.75rem 1rem; text-align: left; border-bottom: 1px solid #1f4865; }
				th { background:#11283b; color: var(--muted); text-transform: uppercase; font-size: 0.75rem; }
				tr:last-child td { border-bottom: none; }
				.badge { display:inline-block; padding:0.15rem 0.6rem; border-radius:999px; font-size:0.7rem; text-transform:uppercase; }
