				.card { background: var(--card); border-radius:8px; padding:1.5rem; margin-bottom:1.5rem; }
				form.stacked { display: grid; gap: 0.8rem; max-width: 480px; }
				form.stacked label { display: grid; gap: 0.3rem; font-size: 0.85rem; color: var(--muted); }
				form.stacked input, form.stacked select, form.stacked textarea {
