import (
	"fmt"
	"time"

	"github.com/harborworks/booking-hub/internal/domain"
)

func formatDateTime(t time.Time) string {
	return t.UTC().Format("2006-01-02 15:04 UTC")
}

func nextHourISO() string {
	t := time.Now().UTC().Add(3 * time.Hour).Truncate(time.Hour)
	return t.Format("2006-01-02T15:04")
}

func nextHourPlusISO() string {
	t := time.Now().UTC().Add(4 * time.Hour).Truncate(time.Hour)
	return t.Format("2006-01-02T15:04")
}

templ MyBookingsPage(username string, blacklisted bool, blReason string, bookings []domain.Booking) {
	@Layout("My Bookings", username) {
		<h2>My bookings</h2>
		if blacklisted {
			<div class="error">
				<strong>Account is blacklisted.</strong> New booking requests are blocked.
				if blReason != "" {
					<br/>Reason: { blReason }
				}
			</div>
		}
		if len(bookings) == 0 {
			<div class="empty">
				No bookings yet. <a href="/bookings/new">Create one</a>.
			</div>
		} else {
			<table>
				<thead>
					<tr>
						<th>Resource</th>
						<th>Start</th>
						<th>End</th>
						<th>Party</th>
						<th>Status</th>
						<th>Actions</th>
					</tr>
				</thead>
				<tbody>
					for _, b := range bookings {
						<tr>
							<td><code>{ b.ResourceID.String()[:8] }…</code></td>
							<td>{ formatDateTime(b.StartTime) }</td>
							<td>{ formatDateTime(b.EndTime) }</td>
							<td>{ fmt.Sprintf("%d", b.PartySize) }</td>
							<td><span class={ "badge", string(b.Status) }>{ string(b.Status) }</span></td>
							<td class="actions">
								if !b.Status.IsTerminal() {
									for _, next := range domain.AllowedNext(b.Status) {
										<button class="btn-inline" onclick={ transitionScript(b.ID.String(), string(next)) }>{ string(next) }</button>
									}
								}
							</td>
						</tr>
					}
				</tbody>
			</table>
			<script>
				function harborTransition(id, target) {
					fetch('/api/bookings/' + id + '/transition', {
						method: 'POST',
						headers: { 'Content-Type': 'application/json' },
						body: JSON.stringify({ target_state: target }),
					}).then(async (res) => {
						if (res.ok) { location.reload(); return; }
						const data = await res.json().catch(() => ({}));
						alert('Transition failed: ' + (data.error || res.statusText));
					});
				}
			</script>
		}
