		Addr:              addr,
		Handler:           router,
		ReadHeaderTimeout: 10 * time.Second,
	}

	go func() {
		logger.Info("http server listening", "addr", addr)
		if err := srv.ListenAndServe(); err != nil && !errors.Is(err, http.ErrServerClosed) {
			logger.Error("http server error", "error", err)
			stop()
		}
	}()

	<-ctx.Done()
	logger.Info("shutdown signal received")

	shutdownCtx, cancel := context.WithTimeout(context.Background(), 15*time.Second)
	defer cancel()
	if err := srv.Shutdown(shutdownCtx); err != nil {
		logger.Error("graceful shutdown failed", "error", err)
	}
	logger.Info("server stopped cleanly")
}

// seedAdminUser creates a default "harbormaster" user on first boot so the
// stack is immediately usable after `docker compose up`. The password is
// printed in the log so the operator can sign in; subsequent boots skip this
// step because the user already exists.
func seedAdminUser(ctx context.Context, pool *pgxpool.Pool, repo repository.UserRepository, logger interface {
	Info(msg string, args ...any)
}) error {
	const (
		username = "harbormaster"
		password = "Harbor@Works2026!"
	)

	if existing, err := repo.GetByUsername(ctx, username); err == nil && existing != nil {
		return nil
	} else if err != nil && !errors.Is(err, domain.ErrNotFound) {
		return err
	}

	hash, err := bcrypt.GenerateFromPassword([]byte(password), bcrypt.DefaultCost)
	if err != nil {
		return err
	}
	u := &domain.User{
		Username:     username,
		PasswordHash: string(hash),
	}
	if err := repo.Create(ctx, u); err != nil {
		return err
	}
	logger.Info("default admin user seeded",
		"username", username,
		"password", password,
		"note", "change this credential before exposing the stack")
	return nil
}

func runHealthcheck() int {
	port := os.Getenv("APP_PORT")
	if port == "" {
		port = "8080"
	}
	url := "http://127.0.0.1:" + port + "/healthz"
	client := &http.Client{Timeout: 3 * time.Second}
	resp, err := client.Get(url)
	if err != nil {
		fmt.Fprintf(os.Stderr, "healthcheck failed: %v\n", err)
		return 1
	}
	defer resp.Body.Close()
	if resp.StatusCode != http.StatusOK {
		fmt.Fprintf(os.Stderr, "healthcheck status %d\n", resp.StatusCode)
		return 1
	}
	return 0
}
"}

