	limit, _ := strconv.Atoi(c.DefaultQuery("limit", "10"))
	out, err := h.svc.TopSessions(c.Request.Context(), days, limit)
	if err != nil {
		writeServiceError(c, err)
		return
	}
	c.JSON(http.StatusOK, gin.H{"top": out, "count": len(out)})
}

