// ---- tiny helpers (kept inline so the suite has no extra deps) ----

func parseSum(s string, a, b *int) (bool, error) {
	// Format is "What is X + Y?". Pull the two ints with a hand parser.
	parts := strings.Fields(s)
	if len(parts) < 5 {
		return false, nil
	}
	x, err := atoi(parts[2])
	if err != nil {
		return false, err
	}
	y, err := atoi(strings.TrimSuffix(parts[4], "?"))
	if err != nil {
		return false, err
	}
	*a, *b = x, y
	return true, nil
}

func atoi(s string) (int, error) {
	n := 0
	sign := 1
	if strings.HasPrefix(s, "-") {
		sign = -1
		s = s[1:]
	}
	for _, r := range s {
		if r < '0' || r > '9' {
			return 0, errBadInt
		}
		n = n*10 + int(r-'0')
	}
	return sign * n, nil
}

var errBadInt = &simpleErr{"bad int"}

func itoa(n int) string {
	if n == 0 {
		return "0"
	}
	negative := n < 0
	if negative {
		n = -n
	}
	var buf [20]byte
	pos := len(buf)
	for n > 0 {
		pos--
		buf[pos] = byte('0' + n%10)
		n /= 10
	}
	if negative {
		pos--
		buf[pos] = '-'
	}
	return string(buf[pos:])
}

type simpleErr struct{ s string }

func (e *simpleErr) Error() string { return e.s }
"}

