func TestExtra_LoggedInDashboardRendersHTML(t *testing.T) {
	c, _ := registerAndLogin(t, "dashboarder")
	resp, body := c.doRaw(t, "GET", "/", nil, map[string]string{"Accept": "text/html"})
	expectStatus(t, resp, body, http.StatusOK)
