	purgeCache(t, admin)
	withBrokenTable(t, db, "resources", func() {
		resp, _ := admin.doRaw(t, "GET", "/api/admin/export/resources.csv", nil, nil)
		if resp.StatusCode < 500 {
			t.Errorf("export csv expected 5xx, got %d", resp.StatusCode)
		}
	})
	purgeCache(t, admin)
}
"}

