37		g.CreatedAt = now
38		g.UpdatedAt = now
39	
40		const q = `
41			INSERT INTO group_reservations
42			  (id, name, organizer_name, organizer_email, capacity, notes, created_at, updated_at)
43			VALUES ($1,$2,$3,$4,$5,$6,$7,$8)
44		`
45		if _, err := r.pool.Exec(ctx, q,
46			g.ID, g.Name, g.OrganizerName, g.OrganizerEmail, g.Capacity, g.Notes, g.CreatedAt, g.UpdatedAt,
47		); err != nil {
48			return fmt.Errorf("insert group: %w", err)
