54		const q = `
55			SELECT id, name, organizer_name, organizer_email, capacity, notes, created_at, updated_at
56			FROM group_reservations WHERE id = $1
57		`
58		row := r.pool.QueryRow(ctx, q, id)
59		g, err := scanGroup(row)
