74			SELECT id, name, organizer_name, organizer_email, capacity, notes, created_at, updated_at
75			FROM group_reservations ORDER BY created_at DESC LIMIT $1 OFFSET $2
76		`
77		rows, err := r.pool.Query(ctx, q, limit, offset)
78		if err != nil {
