14	// AvailabilityWindow represents a single free slot returned by an availability
15	// query. The UI can render these directly.
16	type AvailabilityWindow struct {
17		StartTime time.Time `json:"start_time"`
18		EndTime   time.Time `json:"end_time"`
19	}
20	
21	// AvailabilityResult bundles the resource, the bookings already on its
22	// schedule for the requested day, and the derived free windows.
23	type AvailabilityResult struct {
24		Resource Resource             `json:"resource"`
25		Date     string               `json:"date"`
26		Booked   []domain.Booking     `json:"booked"`
27		Free     []AvailabilityWindow `json:"free"`
28	}
29	
30	// Resource is exported here so handlers don't have to import domain just to
31	// shape the API response. It mirrors domain.Resource.
32	type Resource = domain.Resource
33	
34	type ResourceService struct {
35		resources repository.ResourceRepository
36		bookings  repository.BookingRepository
37		log       *slog.Logger
38	}
39	
40	func NewResourceService(resources repository.ResourceRepository, bookings repository.BookingRepository, log *slog.Logger) *ResourceService {
41		return &ResourceService{resources: resources, bookings: bookings, log: log}
42	}
43	
44	func (s *ResourceService) List(ctx context.Context) ([]domain.Resource, error) {
45		return s.resources.List(ctx)
46	}
47	
48	func (s *ResourceService) Get(ctx context.Context, id uuid.UUID) (*domain.Resource, error) {
49		return s.resources.Get(ctx, id)
50	}
51	
52	// Availability returns booked + free windows for a resource on a given date.
53	// The "open day" is interpreted as 08:00–22:00 local time of the supplied date.
54	func (s *ResourceService) Availability(ctx context.Context, resourceID uuid.UUID, day time.Time) (*AvailabilityResult, error) {
55		res, err := s.resources.Get(ctx, resourceID)
56		if err != nil {
57			return nil, err
58		}
59		booked, err := s.bookings.ListByResourceOnDate(ctx, resourceID, day)
60		if err != nil {
61			return nil, err
62		}
63		open := time.Date(day.Year(), day.Month(), day.Day(), 8, 0, 0, 0, day.Location())
64		close := time.Date(day.Year(), day.Month(), day.Day(), 22, 0, 0, 0, day.Location())
65	
66		free := ComputeFreeWindows(open, close, booked)
67	
68		return &AvailabilityResult{
69			Resource: *res,
70			Date:     day.Format("2006-01-02"),
71			Booked:   booked,
72			Free:     free,
73		}, nil
74	}
75	
76	// ComputeFreeWindows subtracts the union of booking intervals from [open,close).
77	func ComputeFreeWindows(open, close time.Time, booked []domain.Booking) []AvailabilityWindow {
78		if !close.After(open) {
79			return nil
80		}
81		cursor := open
82		out := make([]AvailabilityWindow, 0)
83		for _, b := range booked {
84			bs := b.StartTime
85			if bs.Before(open) {
86				bs = open
87			}
88			be := b.EndTime
89			if be.After(close) {
90				be = close
91			}
92			if !be.After(bs) {
93				continue
94			}
95			if bs.After(cursor) {
96				out = append(out, AvailabilityWindow{StartTime: cursor, EndTime: bs})
97			}
98			if be.After(cursor) {
99				cursor = be
100			}
101		}
102		if cursor.Before(close) {
103			out = append(out, AvailabilityWindow{StartTime: cursor, EndTime: close})
104		}
105		return out
106	}
