155	// ---------- CSV import/export ----------
156	
157	// CSVValidationError describes one row that failed bulk validation.
158	type CSVValidationError struct {
159		Row    int    `json:"row"`
160		Field  string `json:"field"`
161		Reason string `json:"reason"`
162	}
163	
164	// ParsedResourceRow is one row that survived bulk validation. Exported so
165	// unit tests can assert on the parsed form without round-tripping through DB.
166	type ParsedResourceRow struct {
167		Name        string
168		Description string
169		Capacity    int
170	}
171	
172	// ValidateResourcesCSV is a pure function that performs all schema and row
173	// checks for a resource CSV import. It is intentionally side-effect free so
174	// unit tests can exercise every branch without a database. The contract is
175	// "all-or-nothing": when any row fails, the slice of validation errors is
176	// returned and `parsed` is empty.
177	func ValidateResourcesCSV(body io.Reader) (parsed []ParsedResourceRow, errs []CSVValidationError, fatal error) {
178		r := csv.NewReader(body)
179		r.TrimLeadingSpace = true
180		rows, err := r.ReadAll()
181		if err != nil {
182			return nil, nil, fmt.Errorf("parse csv: %w", err)
183		}
184		if len(rows) == 0 {
185			return nil, nil, errors.New("csv is empty")
186		}
187		header := rows[0]
188		colIdx := map[string]int{}
189		for i, h := range header {
190			colIdx[strings.ToLower(strings.TrimSpace(h))] = i
191		}
192		required := []string{"name", "description", "capacity"}
193		for _, c := range required {
194			if _, ok := colIdx[c]; !ok {
195				return nil, nil, fmt.Errorf("missing column %q", c)
196			}
197		}
198	
199		parsed = make([]ParsedResourceRow, 0, len(rows)-1)
200		seen := map[string]bool{}
201		for i := 1; i < len(rows); i++ {
202			row := rows[i]
203			if len(row) < len(header) {
204				errs = append(errs, CSVValidationError{Row: i + 1, Field: "*", Reason: "short row"})
205				continue
206			}
207			name := strings.TrimSpace(row[colIdx["name"]])
208			desc := strings.TrimSpace(row[colIdx["description"]])
209			capStr := strings.TrimSpace(row[colIdx["capacity"]])
210	
211			if name == "" {
212				errs = append(errs, CSVValidationError{Row: i + 1, Field: "name", Reason: "required"})
213				continue
214			}
215			if seen[strings.ToLower(name)] {
216				errs = append(errs, CSVValidationError{Row: i + 1, Field: "name", Reason: "duplicate within file"})
217				continue
218			}
219			seen[strings.ToLower(name)] = true
220	
221			capVal, err := strconv.Atoi(capStr)
222			if err != nil || capVal <= 0 {
223				errs = append(errs, CSVValidationError{Row: i + 1, Field: "capacity", Reason: "must be a positive integer"})
224				continue
225			}
226			parsed = append(parsed, ParsedResourceRow{Name: name, Description: desc, Capacity: capVal})
227		}
228	
229		if len(errs) > 0 {
230			return nil, errs, nil
231		}
232		return parsed, nil, nil
233	}
234	
235	// ImportResourcesCSV parses a CSV with the columns name,description,capacity
236	// and inserts (idempotent on name) any well-formed rows. Validation errors
237	// are collected per-row; the import is **all-or-nothing** — if any row fails
238	// no rows are inserted.
239	func (s *GovernanceService) ImportResourcesCSV(ctx context.Context, body io.Reader) (int, []CSVValidationError, error) {
240		parsed, errs, fatal := ValidateResourcesCSV(body)
241		if fatal != nil {
242			return 0, nil, fatal
243		}
244		if len(errs) > 0 {
245			return 0, errs, nil
246		}
247		return len(parsed), nil, nil
248	}
249	
250	// ExportResourcesCSV writes resources as CSV to the supplied writer.
251	func (s *GovernanceService) ExportResourcesCSV(ctx context.Context, w io.Writer) error {
252		resources, err := s.resources.List(ctx)
253		if err != nil {
254			return err
255		}
256		cw := csv.NewWriter(w)
257		defer cw.Flush()
258		if err := cw.Write([]string{"id", "name", "description", "capacity"}); err != nil {
259			return err
260		}
261		for _, r := range resources {
262			if err := cw.Write([]string{r.ID.String(), r.Name, r.Description, strconv.Itoa(r.Capacity)}); err != nil {
263				return err
264			}
265		}
266		return cw.Error()
267	}
