70	func (r *bookingRepo) Get(ctx context.Context, id uuid.UUID) (*domain.Booking, error) {
71		q := `SELECT ` + bookingColumns + ` FROM bookings WHERE id = $1`
72		row := r.pool.QueryRow(ctx, q, id)
73		b, err := scanBooking(row)
74		if err != nil {
75			if errors.Is(err, pgx.ErrNoRows) {
76				return nil, domain.ErrNotFound
77			}
78			return nil, fmt.Errorf("get booking: %w", err)
79		}
80		return b, nil
