115	func (r *bookingRepo) ListByResourceOnDate(ctx context.Context, resourceID uuid.UUID, day time.Time) ([]domain.Booking, error) {
116		dayStart := time.Date(day.Year(), day.Month(), day.Day(), 0, 0, 0, 0, day.Location())
117		dayEnd := dayStart.Add(24 * time.Hour)
118		q := `SELECT ` + bookingColumns + `
119			FROM bookings
120			WHERE resource_id = $1
121			  AND status <> 'canceled'
122			  AND start_time < $3 AND end_time > $2
123			ORDER BY start_time ASC`
124		rows, err := r.pool.Query(ctx, q, resourceID, dayStart, dayEnd)
125		if err != nil {
