132	func (r *bookingRepo) CountActiveByUserOnDate(ctx context.Context, userID uuid.UUID, day time.Time) (int, error) {
133		dayStart := time.Date(day.Year(), day.Month(), day.Day(), 0, 0, 0, 0, day.Location())
134		dayEnd := dayStart.Add(24 * time.Hour)
135		const q = `
136			SELECT COUNT(*) FROM bookings
137			WHERE user_id = $1
138			  AND status IN ('pending_confirmation','waitlisted','checked_in')
139			  AND start_time >= $2 AND start_time < $3
140		`
141		var count int
142		if err := r.pool.QueryRow(ctx, q, userID, dayStart, dayEnd).Scan(&count); err != nil {
143			return 0, fmt.Errorf("count active bookings: %w", err)
144		}
