148	func (r *bookingRepo) UserHasOverlap(ctx context.Context, userID uuid.UUID, start, end time.Time, exclude *uuid.UUID) (bool, error) {
149		q := `
150			SELECT EXISTS (
151				SELECT 1 FROM bookings
152				WHERE user_id = $1
153				  AND status <> 'canceled'
154				  AND start_time < $3 AND end_time > $2
155				  AND ($4::uuid IS NULL OR id <> $4)
156			)
157		`
158		var exists bool
159		if err := r.pool.QueryRow(ctx, q, userID, start, end, exclude).Scan(&exists); err != nil {
160			return false, fmt.Errorf("user overlap check: %w", err)
161		}
162		return exists, nil
