168				SELECT 1 FROM bookings
169				WHERE resource_id = $1
170				  AND status IN ('pending_confirmation','checked_in')
171				  AND start_time < $3 AND end_time > $2
172				  AND ($4::uuid IS NULL OR id <> $4)
173			)
174		`
