205	// --- helpers ---
206	
207	type rowScanner interface {
208		Scan(dest ...any) error
209	}
210	
211	func sanitisePaging(limit, offset int) (int, int) {
212		if limit <= 0 || limit > 200 {
213			limit = 50
214		}
215		if offset < 0 {
216			offset = 0
217		}
218		return limit, offset
219	}
220	
221	func scanBooking(s rowScanner) (*domain.Booking, error) {
222		var (
223			b       domain.Booking
224			groupID *uuid.UUID
225			status  string
226		)
227		if err := s.Scan(
228			&b.ID, &b.UserID, &b.ResourceID, &groupID, &b.PartySize,
229			&b.StartTime, &b.EndTime, &status, &b.Notes, &b.CreatedAt, &b.UpdatedAt,
230		); err != nil {
231			return nil, err
232		}
233		b.GroupID = groupID
234		b.Status = domain.BookingStatus(status)
235		return &b, nil
236	}
237	
238	func collectBookings(rows pgx.Rows) ([]domain.Booking, error) {
239		out := make([]domain.Booking, 0, 16)
240		for rows.Next() {
241			b, err := scanBooking(rows)
242			if err != nil {
243				return nil, err
244			}
245			out = append(out, *b)
246		}
247		if err := rows.Err(); err != nil {
248			return nil, err
249		}
250		return out, nil
251	}
