16	// BookingPolicy collects the time-based business rules. Centralising them
17	// keeps the constants visible to handlers and tests.
18	type BookingPolicy struct {
19		MinLeadTime    time.Duration // 2h: earliest start time relative to now for a new booking
20		ChangeCutoff   time.Duration // 10m: changes/cancellations forbidden inside this window
21		MaxActivePerDay int           // 3: per-user limit on active bookings on the same calendar day
22	}
23	
24	func DefaultBookingPolicy() BookingPolicy {
25		return BookingPolicy{
26			MinLeadTime:     2 * time.Hour,
27			ChangeCutoff:    10 * time.Minute,
28			MaxActivePerDay: 3,
29		}
30	}
31	
32	type BookingService struct {
33		bookings  repository.BookingRepository
34		resources repository.ResourceRepository
35		users     repository.UserRepository
36		policy    BookingPolicy
37		log       *slog.Logger
38	}
