40	func NewBookingService(
41		bookings repository.BookingRepository,
42		resources repository.ResourceRepository,
43		users repository.UserRepository,
44		log *slog.Logger,
45		policy BookingPolicy,
46	) *BookingService {
47		return &BookingService{bookings: bookings, resources: resources, users: users, log: log, policy: policy}
48	}
49	
50	func (s *BookingService) Policy() BookingPolicy { return s.policy }
51	
52	// CreateInput captures the parameters of a new booking request.
53	type CreateInput struct {
54		UserID     uuid.UUID
55		ResourceID uuid.UUID
56		GroupID    *uuid.UUID
57		PartySize  int
58		StartTime  time.Time
59		EndTime    time.Time
60		Notes      string
61	}
62	
63	// Create applies the full booking policy and persists the result. Bookings
64	// that conflict with another active booking on the same resource are placed
65	// on the waitlist instead of being rejected.
66	func (s *BookingService) Create(ctx context.Context, in CreateInput) (*domain.Booking, error) {
67		// 0. Blacklist gate. Hard block.
68		user, err := s.users.GetByID(ctx, in.UserID)
69		if err != nil {
70			return nil, err
71		}
72		if user.IsBlacklisted {
73			return nil, errors.Join(domain.ErrBlacklisted, errors.New(user.BlacklistReason))
74		}
75	
76		// 1. Resource must exist.
77		if _, err := s.resources.Get(ctx, in.ResourceID); err != nil {
78			return nil, err
79		}
80	
81		// 2. Shape validation.
82		now := time.Now().UTC()
83		in.StartTime = in.StartTime.UTC()
84		in.EndTime = in.EndTime.UTC()
85		if !in.EndTime.After(in.StartTime) {
86			return nil, errors.Join(domain.ErrInvalidInput, errors.New("end_time must be after start_time"))
87		}
88		if in.PartySize <= 0 {
89			in.PartySize = 1
90		}
91	
92		// 3. Lead-time gate (>= 2h from now).
93		if in.StartTime.Before(now.Add(s.policy.MinLeadTime)) {
94			return nil, errors.Join(domain.ErrLeadTime,
95				fmt.Errorf("start_time must be at least %s in the future", s.policy.MinLeadTime))
96		}
97	
98		// 4. Daily active-booking cap (3 per user per calendar day).
99		count, err := s.bookings.CountActiveByUserOnDate(ctx, in.UserID, in.StartTime)
100		if err != nil {
101			return nil, err
102		}
103		if count >= s.policy.MaxActivePerDay {
104			return nil, errors.Join(domain.ErrDailyLimit,
105				fmt.Errorf("user already has %d active bookings on %s", count, in.StartTime.Format("2006-01-02")))
106		}
107	
108		// 5. Per-user overlap (no double-booking the same window across resources).
109		overlap, err := s.bookings.UserHasOverlap(ctx, in.UserID, in.StartTime, in.EndTime, nil)
110		if err != nil {
111			return nil, err
112		}
113		if overlap {
114			return nil, errors.Join(domain.ErrOverlap, errors.New("you already have a booking in this window"))
115		}
116	
117		// 6. Resource conflict ⇒ waitlist instead of reject.
118		resourceBusy, err := s.bookings.ResourceHasOverlap(ctx, in.ResourceID, in.StartTime, in.EndTime, nil)
119		if err != nil {
120			return nil, err
121		}
122		status := domain.StatusPendingConfirmation
123		if resourceBusy {
124			status = domain.StatusWaitlisted
125		}
126	
127		b := &domain.Booking{
128			UserID:     in.UserID,
129			ResourceID: in.ResourceID,
130			GroupID:    in.GroupID,
131			PartySize:  in.PartySize,
132			StartTime:  in.StartTime,
133			EndTime:    in.EndTime,
134			Status:     status,
135			Notes:      in.Notes,
136		}
137		if err := b.Validate(); err != nil {
138			return nil, err
139		}
140		if err := s.bookings.Create(ctx, b); err != nil {
141			return nil, err
142		}
143		s.log.Info("booking created",
144			"id", b.ID, "user_id", b.UserID, "resource_id", b.ResourceID,
145			"status", b.Status, "start", b.StartTime, "end", b.EndTime)
146		return b, nil
147	}
