161	// Transition moves a booking to a new state, enforcing both the state machine
162	// and the time-based cutoff window. The actor (user) must own the booking.
163	func (s *BookingService) Transition(ctx context.Context, actorID uuid.UUID, bookingID uuid.UUID, target domain.BookingStatus) (*domain.Booking, error) {
164		b, err := s.bookings.Get(ctx, bookingID)
165		if err != nil {
166			return nil, err
167		}
168		if b.UserID != actorID {
169			return nil, domain.ErrForbidden
170		}
171		if !domain.CanTransition(b.Status, target) {
172			return nil, errors.Join(domain.ErrInvalidTransition,
173				fmt.Errorf("cannot move %s -> %s", b.Status, target))
174		}
175	
176		// Cutoff: cancellations and check-ins are blocked inside the cutoff window
177		// (less than 10 minutes before start). Auto-completing a checked-in
178		// booking is allowed because it represents the natural end of stay.
179		now := time.Now().UTC()
180		timeToStart := b.StartTime.Sub(now)
181		cutoffActive := timeToStart > 0 && timeToStart < s.policy.ChangeCutoff
182		if cutoffActive && (target == domain.StatusCanceled || target == domain.StatusWaitlisted || target == domain.StatusPendingConfirmation) {
183			return nil, errors.Join(domain.ErrCutoff,
184				fmt.Errorf("changes are locked %s before start_time", s.policy.ChangeCutoff))
185		}
186	
187		// When promoting waitlisted -> pending_confirmation, the resource must be free again.
188		if b.Status == domain.StatusWaitlisted && target == domain.StatusPendingConfirmation {
189			busy, err := s.bookings.ResourceHasOverlap(ctx, b.ResourceID, b.StartTime, b.EndTime, &b.ID)
190			if err != nil {
191				return nil, err
192			}
193			if busy {
194				return nil, errors.Join(domain.ErrConflict, errors.New("resource is still occupied"))
195			}
196		}
197	
198		if err := s.bookings.UpdateStatus(ctx, bookingID, target); err != nil {
199			return nil, err
200		}
201		b.Status = target
202		b.UpdatedAt = now
203		s.log.Info("booking transition", "id", b.ID, "to", target, "actor", actorID)
204		return b, nil
205	}
