58	// Emit fans out an event to all matching enabled webhooks. Each delivery is
59	// queued; the actual HTTP call happens in RunDeliveryCycle so the request
60	// path stays fast and retries can use exponential backoff.
61	func (s *WebhookService) Emit(ctx context.Context, eventType string, payload any) error {
62		hooks, err := s.repo.List(ctx)
63		if err != nil {
64			return err
65		}
66		body, err := json.Marshal(payload)
67		if err != nil {
68			return err
69		}
70		now := time.Now().UTC()
71		for _, h := range hooks {
72			if !h.Enabled {
73				continue
74			}
75			if !filterAccepts(h.EventFilter, eventType) {
76				continue
77			}
78			// Apply field mapping: rename top-level keys per the mapping config.
79			mapped := applyFieldMapping(body, h.FieldMapping)
80			_ = s.repo.EnqueueDelivery(ctx, &domain.WebhookDelivery{
81				WebhookID:     h.ID,
82				EventType:     eventType,
83				Payload:       mapped,
84				NextAttemptAt: now,
85				Status:        "pending",
86			})
87		}
88		return nil
89	}
90	
91	// RunDeliveryCycle is invoked periodically by the jobs runner. It pulls
92	// pending deliveries that are due, attempts each one, and reschedules with
93	// exponential backoff up to 5 attempts before marking 'dead'.
94	func (s *WebhookService) RunDeliveryCycle(ctx context.Context) error {
95		now := time.Now().UTC()
96		pending, err := s.repo.DequeuePending(ctx, now, 25)
97		if err != nil {
98			return err
99		}
100		for _, d := range pending {
101			s.attempt(ctx, d)
102		}
103		return nil
104	}
105	
106	func (s *WebhookService) attempt(ctx context.Context, d domain.WebhookDelivery) {
107		hook, err := s.repo.Get(ctx, d.WebhookID)
108		if err != nil {
109			_ = s.repo.UpdateDeliveryAttempt(ctx, d.ID, d.Attempts+1, "failed", "missing webhook", time.Now().UTC().Add(time.Hour))
110			return
111		}
112		req, err := http.NewRequestWithContext(ctx, http.MethodPost, hook.TargetURL, bytes.NewReader(d.Payload))
113		if err != nil {
114			_ = s.repo.UpdateDeliveryAttempt(ctx, d.ID, d.Attempts+1, "failed", err.Error(), time.Now().UTC().Add(time.Hour))
115			return
116		}
117		req.Header.Set("Content-Type", "application/json")
118		req.Header.Set("X-HarborWorks-Event", d.EventType)
119		if hook.Secret != "" {
120			req.Header.Set("X-HarborWorks-Secret", hook.Secret)
121		}
122	
123		resp, err := s.client.Do(req)
124		attempts := d.Attempts + 1
125		if err != nil {
126			s.handleFailure(ctx, d.ID, attempts, "transport error: "+err.Error())
127			return
128		}
129		defer resp.Body.Close()
130		body, _ := io.ReadAll(io.LimitReader(resp.Body, 4<<10))
131		if resp.StatusCode >= 200 && resp.StatusCode < 300 {
132			_ = s.repo.UpdateDeliveryAttempt(ctx, d.ID, attempts, "delivered", fmt.Sprintf("%d %s", resp.StatusCode, string(body)), time.Now().UTC())
133			return
134		}
135		s.handleFailure(ctx, d.ID, attempts, fmt.Sprintf("%d %s", resp.StatusCode, string(body)))
136	}
137	
138	// WebhookBackoff returns the duration to wait before retry attempt N. Pure
139	// function so unit tests can validate the schedule (1s, 2s, 4s, 8s, 16s).
140	func WebhookBackoff(attempts int) time.Duration {
141		if attempts <= 0 {
142			return 0
143		}
144		return time.Duration(1<<uint(attempts-1)) * time.Second
145	}
146	
147	// NextWebhookStatus returns the status that should be persisted after the
148	// given attempt fails. After WebhookMaxAttempts the delivery is dead.
149	func NextWebhookStatus(attempts int) string {
150		if attempts >= WebhookMaxAttempts {
151			return "dead"
152		}
153		return "pending"
154	}
155	
156	func (s *WebhookService) handleFailure(ctx context.Context, id uuid.UUID, attempts int, reason string) {
157		status := NextWebhookStatus(attempts)
158		if status == "dead" {
