120	// POST /api/admin/import/resources — multipart CSV upload, all-or-nothing.
121	func (h *GovernanceHandler) ImportResources(c *gin.Context) {
122		u := middleware.CurrentUser(c)
123		if u == nil || !u.IsAdmin {
124			c.JSON(http.StatusForbidden, gin.H{"error": "admin only"})
125			return
126		}
127		file, _, err := c.Request.FormFile("file")
128		if err != nil {
129			c.JSON(http.StatusBadRequest, gin.H{"error": "expected multipart 'file' field"})
130			return
131		}
132		defer file.Close()
133		count, errs, err := h.svc.ImportResourcesCSV(c.Request.Context(), file)
134		if err != nil {
135			c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
136			return
137		}
138		if len(errs) > 0 {
139			c.JSON(http.StatusUnprocessableEntity, gin.H{
140				"status": "rejected",
141				"errors": errs,
142				"detail": "all-or-nothing: no rows imported",
143			})
144			return
145		}
146		c.JSON(http.StatusOK, gin.H{"status": "ok", "would_insert": count})
147	}
