115	func (r *userRepo) RecordFailedLogin(ctx context.Context, id uuid.UUID, lockUntil *time.Time) error {
116		const q = `
117			UPDATE users
118			SET failed_attempts = failed_attempts + 1,
119			    locked_until    = COALESCE($2, locked_until),
120			    updated_at      = NOW()
121			WHERE id = $1
122		`
123		_, err := r.pool.Exec(ctx, q, id, lockUntil)
124		if err != nil {
125			return fmt.Errorf("record failed login: %w", err)
126		}
127		return nil
128	}
