130	func (r *userRepo) ResetFailedLogin(ctx context.Context, id uuid.UUID, loginAt time.Time) error {
131		const q = `
132			UPDATE users
133			SET failed_attempts = 0,
134			    locked_until    = NULL,
135			    last_login_at   = $2,
136			    updated_at      = NOW()
137			WHERE id = $1
138		`
139		_, err := r.pool.Exec(ctx, q, id, loginAt)
140		if err != nil {
141			return fmt.Errorf("reset failed login: %w", err)
142		}
143		return nil
144	}
