147		const q = `
148			UPDATE users SET is_blacklisted = $2, blacklist_reason = $3, updated_at = NOW() WHERE id = $1
149		`
150		tag, err := r.pool.Exec(ctx, q, id, blacklisted, reason)
151		if err != nil {
152			return fmt.Errorf("set blacklist: %w", err)
153		}
154		if tag.RowsAffected() == 0 {
155			return domain.ErrNotFound
156		}
157		return nil
