168			&u.ID, &u.Username, &u.PasswordHash, &u.IsBlacklisted, &u.BlacklistReason,
169			&u.IsAdmin, &anonymizedAt,
170			&u.FailedAttempts, &lockedUntil, &lastLogin, &u.CreatedAt, &u.UpdatedAt,
171		); err != nil {
