	if err := h.auth.ChangePassword(c.Request.Context(), user.ID, req.CurrentPassword, req.NewPassword); err != nil {
		writeAuthError(c, h.auth, err)
		return
	}
	c.JSON(http.StatusOK, gin.H{"status": "rotated"})
