			.gb-bar { width:100%; height:14px; background:#1f4865; border-radius:7px; overflow:hidden; margin-top:6px; }
			.gb-bar > div { height:100%; background: var(--accent); }
			.gb-card { padding:1rem 1.25rem; margin-bottom:1rem; }
			.gb-meta { color: var(--muted); font-size:0.85rem; }
		</style>
		<h2>Group buys</h2>
		if len(buys) == 0 {
			<div class="empty">No group buys yet. Use <code>POST /api/group-buys</code> to start one.</div>
		} else {
			for _, g := range buys {
				<div class="card gb-card">
					<h3 style="margin:0;">
						<a href={ templ.SafeURL("/group-buys/" + g.ID.String()) }>{ g.Title }</a>
						&nbsp;<span class={ gbStatusBadge(string(g.Status)) }>{ string(g.Status) }</span>
					</h3>
					<p class="gb-meta">{ gbHeadline(g) } · { gbDeadlineHuman(g) }</p>
					<p>{ fmt.Sprintf("%d / %d confirmed (capacity %d)", g.Confirmed(), g.Threshold, g.Capacity) }</p>
					<div class="gb-bar"><div style={ gbBarStyle(g) }></div></div>
				</div>
			}
		}
	}
}

templ GroupBuyDetail(username string, g domain.GroupBuy, progress *service.Progress, participants []map[string]any, isMember bool) {
	@Layout("Group buy: " + g.Title, username) {
		<style>
			.gb-bar { width:100%; height:18px; background:#1f4865; border-radius:9px; overflow:hidden; margin:0.5rem 0 1rem; }
			.gb-bar > div { height:100%; background: var(--accent); transition: width 0.3s; }
			.gb-failed { background: var(--err); }
		</style>
		<h2>{ g.Title } &nbsp;<span class={ gbStatusBadge(string(g.Status)) }>{ string(g.Status) }</span></h2>
		<p class="muted">{ gbHeadline(g) } · { gbDeadlineHuman(g) }</p>

		if g.Status == domain.GroupBuyExpired || g.Status == domain.GroupBuyCanceled {
			<div class="error">
				<strong>This group buy did not succeed.</strong>
				if g.Status == domain.GroupBuyExpired {
					Threshold of { fmt.Sprintf("%d", g.Threshold) } seats was not reached before the deadline.
				} else {
					The organiser cancelled it.
				}
				No charges are made; participants are released.
			</div>
		} else if g.Status == domain.GroupBuyFinalized {
			<div class="ok">
				<strong>Finalised.</strong> { fmt.Sprintf("%d seats confirmed.", g.Confirmed()) }
			</div>
		}

		<p>{ g.Description }</p>

		<div class="card">
			<p style="margin:0;">
				<strong>{ fmt.Sprintf("%d / %d seats confirmed", g.Confirmed(), g.Threshold) }</strong>
				if progress != nil {
					&nbsp;· { fmt.Sprintf("%d remaining out of %d capacity", progress.RemainingSlots, progress.Capacity) }
				}
			</p>
			<div class="gb-bar">
				if g.Status == domain.GroupBuyExpired {
					<div class="gb-failed" style="width:100%"></div>
				} else {
					<div style={ gbBarStyle(g) }></div>
				}
			</div>
			<p class="muted" style="margin:0;">
				Window: { formatDateTime(g.StartsAt) } → { formatDateTime(g.EndsAt) }<br/>
				Deadline: { formatDateTime(g.Deadline) }
			</p>
		</div>

		if username != "" && g.Status == domain.GroupBuyOpen {
			if isMember {
				<p class="ok" style="margin:0;">You have already joined this group buy.</p>
			} else {
				<form id="gbJoin" class="stacked" style="max-width:300px;">
					<label>
						Quantity
						<input type="number" name="quantity" min="1" value="1" required/>
					</label>
					<button type="submit">Join group buy</button>
				</form>
				<script>
					document.getElementById('gbJoin').addEventListener('submit', async (e) => {
						e.preventDefault();
						const qty = parseInt(e.target.quantity.value, 10);
						const key = 'ui-' + crypto.randomUUID();
						const res = await fetch(window.location.pathname.replace('/group-buys/', '/api/group-buys/') + '/join', {
							method: 'POST',
							headers: { 'Content-Type': 'application/json', 'Idempotency-Key': key },
							body: JSON.stringify({ quantity: qty }),
						});
						if (res.ok) { window.location.reload(); return; }
						const data = await res.json().catch(() => ({}));
						alert('Join failed: ' + (data.error || res.statusText));
					});
				</script>
			}
		}

		<h3>Participants</h3>
		if len(participants) == 0 {
			<div class="empty">Nobody has joined yet. Be the first.</div>
		} else {
			<table>
				<thead><tr><th>Member</th><th>Seats</th><th>Joined</th></tr></thead>
				<tbody>
					for _, p := range participants {
						<tr>
							<td>{ fmt.Sprintf("%v", p["masked_name"]) }</td>
							<td>{ fmt.Sprintf("%v", p["quantity"]) }</td>
							<td>{ fmt.Sprintf("%v", p["joined_at"]) }</td>
						</tr>
					}
				</tbody>
			</table>
		}
	}
}
"}

