// AdminAnalyticsPageData carries everything the dashboard needs in a single
// struct so the handler doesn't have to thread half a dozen positional
// parameters into the templ component.
type AdminAnalyticsPageData struct {
	Username  string
	Top       []domain.TopSession
	Day7      []domain.TrendBucket
	Day30     []domain.TrendBucket
	Day90     []domain.TrendBucket
	Anomalies []domain.AnomalyAlert
	EventType string
}

templ AdminAnalyticsPage(data AdminAnalyticsPageData) {
	@Layout("Admin · analytics", data.Username) {
		<style>
			.aa-grid { display:grid; grid-template-columns:1fr 1fr; gap:1.5rem; }
			@media (max-width:880px) { .aa-grid { grid-template-columns:1fr; } }
			.aa-spark { display:flex; align-items:flex-end; gap:2px; height:60px; }
