templ trendCard(label string, buckets []domain.TrendBucket) {
	<div class="card">
		<h3 style="margin-top:0;">{ label }</h3>
		if len(buckets) == 0 {
			<div class="empty">No data.</div>
		} else {
			<div class="aa-spark">
				for _, b := range buckets {
					<div style={ trendBarStyle(b, buckets) } title={ fmt.Sprintf("%s: %d", b.BucketStart.Format("Jan 2"), b.Count) }></div>
				}
			</div>
			<p class="muted" style="margin:0.5rem 0 0;">{ fmt.Sprintf("%d buckets · total %d", len(buckets), trendTotal(buckets)) }</p>
		}
	</div>
}

func trendTotal(b []domain.TrendBucket) int64 {
	var t int64
	for _, x := range b {
		t += x.Count
	}
	return t
}

func trendBarStyle(b domain.TrendBucket, all []domain.TrendBucket) string {
	max := int64(1)
	for _, x := range all {
		if x.Count > max {
			max = x.Count
		}
	}
	h := (b.Count * 60) / max
	if h < 2 {
		h = 2
	}
	return fmt.Sprintf("height:%dpx;", h)
}
"}

