			<div class="empty">No data.</div>
		} else {
			@trendSpark(buckets)
			<p class="muted" style="margin:0.5rem 0 0;">{ fmt.Sprintf("%d buckets · total %d", len(buckets), trendTotal(buckets)) }</p>
		}
	</div>
}

// trendSpark renders the sparkline as raw HTML so the per-bar style="height:Npx"
// attribute does not need a templ string-attribute expression (which the
// templ parser rejects). The output is escaped at build time.
func trendSpark(buckets []domain.TrendBucket) templ.Component {
	max := int64(1)
	for _, x := range buckets {
		if x.Count > max {
			max = x.Count
		}
	}
	var html string
	html += `<div class="aa-spark">`
	for _, b := range buckets {
		h := (b.Count * 60) / max
		if h < 2 {
			h = 2
		}
		title := templ.EscapeString(fmt.Sprintf("%s: %d", b.BucketStart.Format("Jan 2"), b.Count))
		html += fmt.Sprintf(`<div style="height:%dpx" title="%s"></div>`, h, title)
	}
	html += `</div>`
	return templ.Raw(html)
}

func trendTotal(b []domain.TrendBucket) int64 {
	var t int64
	for _, x := range b {
		t += x.Count
	}
	return t
}"}

