	var html string
	html += `<div class="aa-spark">`
	for _, b := range buckets {
		h := (b.Count * 60) / max
		if h < 2 {
			h = 2
		}
		title := templ.EscapeString(fmt.Sprintf("%s: %d", b.BucketStart.Format("Jan 2"), b.Count))
		html += fmt.Sprintf(`<div style="height:%dpx" title="%s"></div>`, h, title)
	}
	html += `</div>`
	return templ.Raw(html)
}

func trendTotal(b []domain.TrendBucket) int64 {
	var t int64
	for _, x := range b {
		t += x.Count
	}
	return t
}"}

